
theta1 = deg2rad(70); %[control:slider:090c]{"position":[18,20]}
theta2 = deg2rad(50); %[control:slider:0e33]{"position":[18,20]}
theta3 = deg2rad(-40); %[control:slider:062c]{"position":[18,21]}
theta4 = deg2rad(0); %[control:slider:97cf]{"position":[18,19]}

a1 = dh_link_to_transformation_matrix(0, pi/2, 0, theta1);
a2 = dh_link_to_transformation_matrix(0.15, 0, 0, theta2-pi/4);
a3 = dh_link_to_transformation_matrix(0.15, 0, 0, theta3-pi/4);
a4 = dh_link_to_transformation_matrix(0, pi/2, 0, theta4); % d4 might be something
T = a1 * a2 * a3 * a4 % shows end effector position %[output:4be9f313]
T02 = a1 * a2;
T03 = a1 * a2 * a3; % should overlap with end effector

%[text] 3D Plot
plot3(0,0,0, "bo", MarkerFaceColor="b") %[output:72cf2457]
hold on %[output:72cf2457]
plot3(T02(1,4), T02(2,4), T02(3,4), "go", MarkerFaceColor="g") %[output:72cf2457]
plot3(T03(1,4), T03(2,4), T03(3,4), "yo", MarkerFaceColor="y") %[output:72cf2457]
plot3(T(1,4), T(2,4), T(3,4), "ro", MarkerFaceColor="r") %[output:72cf2457]
legend("Origin", "J2", "J3", "End effector") %[output:72cf2457]
grid on %[output:72cf2457]
grid minor %[output:72cf2457]
hold off %[output:72cf2457]
xlim([-0.5 0.5]) %[output:72cf2457]
ylim([-0.5 0.5]) %[output:72cf2457]
zlim([-0.5 0.5]) %[output:72cf2457]
xlabel("X") %[output:72cf2457]
ylabel("Y") %[output:72cf2457]
zlabel("Z") %[output:72cf2457]
%[text] Let's now plot the origin and the location of the end effector in a top down view (XY plane) and a front view (XZ plane)
plot(0, 0, "bo", MarkerFaceColor="b") %[output:47eae871]
hold on %[output:47eae871]
plot(T(1,4), T(2,4), "ro", MarkerFaceColor="r") %[output:47eae871]
plot(T02(1,4), T02(2,4), "o") %[output:47eae871]
plot(T03(1,4), T03(2,4), "o") %[output:47eae871]

hold off %[output:47eae871]
title("Top down view (XY) plane") %[output:47eae871]
legend("origin", "end effector") %[output:47eae871]
xlim([-0.5 0.5]) %[output:47eae871]
ylim([-0.5 0.5]) %[output:47eae871]
xlabel("X") %[output:47eae871]
ylabel("Y") %[output:47eae871]

% Plot the front view (XZ) plane
figure; %[output:9c2f007b]
plot(0, 0, "bo", MarkerFaceColor="b") %[output:9c2f007b]
hold on %[output:9c2f007b]
plot(T(1,4), T(3,4), "ro", MarkerFaceColor="r") %[output:9c2f007b]
plot(T02(1,4), T02(3,4), "o") %[output:9c2f007b]
plot(T03(1,4), T03(3,4), "o") %[output:9c2f007b]
hold off %[output:9c2f007b]
title("Front view (XZ) plane") %[output:9c2f007b]
legend("origin", "end effector") %[output:9c2f007b]
xlim([-0.5 0.5]) %[output:9c2f007b]
ylim([-0.5 0.5]) %[output:9c2f007b]
xlabel("X") %[output:9c2f007b]
ylabel("Z") %[output:9c2f007b]

% Plot the front view (YZ) plane
figure; %[output:14e55329]
plot(0, 0, "bo", MarkerFaceColor="b") %[output:14e55329]
hold on %[output:14e55329]
plot(T(2,4), T(3,4), "ro", MarkerFaceColor="r") %[output:14e55329]
plot(T02(2,4), T02(3,4), "o") %[output:14e55329]
plot(T03(2,4), T03(3,4), "o") %[output:14e55329]
hold off %[output:14e55329]
title("Side view (YZ) plane") %[output:14e55329]
legend("origin", "end effector") %[output:14e55329]
xlim([-0.5 0.5]) %[output:14e55329]
ylim([-0.5 0.5]) %[output:14e55329]
xlabel("Y") %[output:14e55329]
ylabel("Z") %[output:14e55329]

